'use client'

import Lottie from "lottie-react"
import { motion, useAnimationControls } from "framer-motion"
import { useEffect, useRef, useState } from "react"
import tagAnimation from "@/assets/animations/tag-jiggle.json"

export default function AnimatedTagHeader() {
  const [showText, setShowText] = useState(false)
  const controls = useAnimationControls()
  const containerRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    if (!containerRef.current) return

    const width = containerRef.current.offsetWidth
    const iconWidth = 96
    const padding = 24

    controls
      .start({
        x: padding,
        opacity: 1,
        transition: { duration: 1.2, ease: "easeOut" },
      })
      .then(() => setShowText(true))
  }, [])

  return (
    <div
      ref={containerRef}
      className="relative mb-10 min-h-[6rem] flex items-center overflow-visible"
    >
      {/* This motion.div moves the Lottie container */}
      <motion.div
        initial={{ x: -100, opacity: 0 }}
        animate={controls}
        className="w-24 h-24"
      >
        {/* This div wraps Lottie to avoid animation conflicts */}
        <div className="w-full h-full">
          <Lottie
            animationData={tagAnimation}
            loop
            autoplay
            style={{ width: 20, height: 20, transform: "scale(3)" }}
          />
        </div>
      </motion.div>

      {/* Title + Description */}
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: showText ? 1 : 0 }}
        transition={{ duration: 0.6, delay: 0.2 }}
        className="ml-4 flex flex-col md:flex-row md:items-end md:justify-between w-full"
      >
        <h1 className="text-3xl md:text-4xl font-bold">Explore by Topics</h1>
        <p className="text-slate-400 text-sm md:text-base md:text-right max-w-xl mt-2 md:mt-0">
          Click on a topic to discover relevant posts.
        </p>
      </motion.div>
    </div>
  )
}
